// Script: generar_137_guardar_todos_png_chiqui.js
// Escribe los 13 PNG de Chiqui en public/chiqui/
// No toca ningun componente — solo guarda las imagenes.
// Catalogo completo:
//   chiqui_lupa.png       → con lupa (observacion)
//   chiqui_lentes.png     → con lentes nerd (tips)
//   chiqui_doctor.png     → con estetoscopio (salud)
//   chiqui_pregunta.png   → pensativo con ? (duda)
//   chiqui_caca.png       → con caca (heces)
//   chiqui_corazon.png    → con corazon (bienestar/amor)
//   chiqui_guino.png      → guinando (alegre)
//   chiqui_ladeado.png    → ladeado (curioso)
//   chiqui_feliz.png      → cara feliz (normal/ok)
//   chiqui_durmiendo.png  → durmiendo ZZZ (descanso/carga)
//   chiqui_emocionado.png → con destellos (logro)
//   chiqui_comiendo.png   → con bowl (alimentacion)
//   chiqui_cool.png       → con lentes sol (cool/racha)

const fs = require('fs'); const path = require('path');
function png(relPath, b64) {
  const f = path.join(...relPath.split('/'));
  const d = path.dirname(f);
  if (!fs.existsSync(d)) fs.mkdirSync(d, { recursive: true });
  fs.writeFileSync(f, Buffer.from(b64, 'base64'));
  console.log('OK: ' + f);
}
png('public/chiqui/chiqui_lupa.png', "");
png('public/chiqui/chiqui_lentes.png', "");
png('public/chiqui/chiqui_doctor.png', "");
png('public/chiqui/chiqui_pregunta.png', "");
